+export fn PyCodec_LookupError(name: [*:0]const u8) callconv(.c) ?*cpython.PyObject {
+    _ = name;
+    // TODO: Look up registered error handler
+    PyErr_SetString(@ptrFromInt(0), "PyCodec_LookupError not implemented");
+    return null;
